def page(j):
    stats=''.join(f'<div class="stat"><span>{k}</span><b>{v}</b></div>' for k,v in j['metrics'])
    modules=''.join(f'<div class="card"><b>{m}</b><p>{j["angle"]}</p></div>' for m in j['modules'])
    events=''.join(f'<div class="event"><span>{e}</span><strong style="color:var(--accent)">active</strong></div>' for e in j['events'])
    flow=''.join(f'<div class="step"><div class="num">{i}</div><b>{m}</b></div>' for i,m in enumerate(j['modules'],1))
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{j['title']}</title><style>{CSS}</style></head><body><div class="page" style="--accent:{j['accent']}"><div class="wrap"><header class="nav"><div class="brand"><div class="logo"></div><div><b>Janis Agic — Premium AI Automation Demo</b><div class="muted">Built as a visual proof-of-concept for the Upwork proposal</div></div></div><div class="pill">{j['budget']} • Client-facing preview</div></header><main class="hero"><section><div class="eyebrow">{j['client']}</div><h1>{j['title']}</h1><p class="lead">A polished MVP blueprint showing how the requested system can work in practice using {j['stack']}. This is designed to make the workflow clear, credible, and easy to discuss before build starts.</p><div class="disclaimer">Disclaimer: All displayed data, names, messages, and metrics are fictional and shown for visual demonstration purposes only.</div><div class="actions"><a class="btn" href="#workflow">View workflow</a><a class="btn secondary" href="#modules">System modules</a></div></section><section class="panel"><div class="screenbar"><i class="dot"></i><i class="dot"></i><i class="dot"></i><span class="muted">premium-demo.janisagic/{j['slug']}</span></div><div class="dash"><div class="widget"><h3>Automation readiness</h3><div class="big">94%</div><div class="bar"><i style="width:94%"></i></div></div><div class="widget"><h3>Manual work reduced</h3><div class="big">68%</div><div class="bar"><i style="width:68%"></i></div></div><div class="widget" style="grid-column:1/-1"><h3>Live workflow events</h3>{events}</div></div></section></main><section class="stats">{stats}</section><section id="modules" class="section"><h2>Premium MVP modules</h2><div class="modules">{modules}</div></section><section id="workflow" class="section"><h2>Proposed workflow</h2><div class="flow">{flow}</div></section><footer class="footer"><span>Prepared by Janis Agic</span><span>{j['budget']} • focused MVP first, expandable after validation</span></footer></div></div></body></html>'''

for j in jobs:
    d=publish/j['slug']; d.mkdir(parents=True, exist_ok=True)
    (d/'index.html').write_text(page(j), encoding='utf-8')

